scwin.ds_orderWrkPath_ondataload = async function () {
	if (ds_order.getRowCount() > 0 && ds_orderWrkPath.getRowCount() == 0) {
		await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
	} else {
        gr_odrWrkPathStep.setReadOnly("grid", true);
	}	
};

scwin.ds_orderWrkPathStep_ondataload = async function () {
	if (ds_order.getRowCount() > 0 && ds_orderWrkPath.getRowCount() > 0 && ds_orderWrkPathStep.getRowCount() == 0) {
		await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
	} else {
        totalRows.setValue(ds_orderWrkPathStep.getRowCount());      
	}
};

scwin.ds_orderWrkPath_onrowpositionchange = function (info) {
    scwin.v_row = 0;

	//ds_orderWrkPathStep.filter();
    scwin.f_onFilter();
    totalRows.setValue(ds_orderWrkPathStep.getRowCount());

	// 작업장구분이 운송인 경우 작업장 정보를 표시하지 않는다.
	for (var i = 0; i < ds_orderWrkPathStep.getRowCount(); i++) {
		if ($c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(i, "wrkPlClsCd"))) {
  			ds_orderWrkPathStep.setCellData(i, "dptWrkPlNm", "");
  		}
  	}

  	ds_orderWrkPathStep.modifyAllStatus("R");
    ds_orderWrkPathStep.reform();

	if (ds_order.getCellData(ds_order.getRowPosition(), "transCargoClsCd") == DsConstants.ODR_BULK) {
        var commSortExpr = {};
        commSortExpr.sortIndex = "odrNo commSeq odrWrkPathSeq odrWrkStpSeq";
        commSortExpr.sortOrder = "1 1 1 1";   // -1 내림차순, 1 오름차순 
        ds_orderWrkPathStep.multisort(commSortExpr);
	} else {
        var cntrSortExpr = {};
        cntrSortExpr.sortIndex = "odrNo cntrSeq odrWrkPathSeq odrWrkStpSeq";
        cntrSortExpr.sortOrder = "1 1 1 1";   // -1 내림차순, 1 오름차순 
        ds_orderWrkPathStep.multisort(cntrSortExpr);  
	}

    for (var i = 0; i < ds_orderWrkPathStep.getRowCount(); i++) {
        // 작업시작일자, 작업시작시간 변경시 이전 row의 작업종료일자, 작업종료시간 변경
        if (i > 0) {
            if ($c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(i - 1, "wrkEndDt").trim()) && !$c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(i, "wrkStDt").trim()) && ds_orderWrkPathStep.getCellData(i, "wrkStDt") != ds_orderWrkPathStep.getCellData(i - 1, "wrkEndDt")) {
                ds_orderWrkPathStep.setCellData(i - 1, "wrkEndDt", ds_orderWrkPathStep.getCellData(i, "wrkStDt"));
            }

            if ($c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(i - 1, "wrkEndHh").trim()) && !$c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(i, "wrkStHh").trim()) && ds_orderWrkPathStep.getCellData(i, "wrkStDt") != ds_orderWrkPathStep.getCellData(i - 1, "wrkEndHh")) {
                ds_orderWrkPathStep.setCellData(i - 1, "wrkEndHh", ds_orderWrkPathStep.getCellData(i, "wrkStHh"));
            }
        }
        // 작업종료일자, 작업종료시간 변경시 이후 row의 작업시작일자, 작업시작시간 변경
        if (i < ds_orderWrkPathStep.getRowCount() - 1) {
            if ($c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(i + 1, "wrkStDt").trim()) && !$c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(i, "wrkEndDt").trim()) && ds_orderWrkPathStep.getCellData(i, "wrkEndDt") != ds_orderWrkPathStep.getCellData(i + 1, "wrkStDt")) {
                ds_orderWrkPathStep.setCellData(i + 1, "wrkStDt", ds_orderWrkPathStep.getCellData(i, "wrkEndDt"));
            }

            if ($c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(i + 1, "wrkStHh").trim()) && !$c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(i, "wrkEndHh").trim()) && ds_orderWrkPathStep.getCellData(i, "wrkEndHh") != ds_orderWrkPathStep.getCellData(i + 1, "wrkStHh")) {
                ds_orderWrkPathStep.setCellData(i + 1, "wrkStHh", ds_orderWrkPathStep.getCellData(i, "wrkEndHh"));
            }
        }   
    }

	/**
	* 첫번째 Row의 작업시작일자, 작업시작시간 완성하기
	* 첫번째 Row의 작업시작일자, 작업시작시간 입력되지 않은경우
	* 오더 시작일자, 시작시간을
	* 첫번째 Row의 작업시작일자, 작업시작시간으로 설정하기
	**/
	if ($c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(0, "wrkStDt")))
		ds_orderWrkPathStep.setCellData(0, "wrkStDt", ds_order.getCellData(0, "wrkStDt"));

	if ($c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(0, "wrkStHh")))
		ds_orderWrkPathStep.setCellData(0, "wrkStHh", ds_order.getCellData(0, "wrkStHh"));

	/**
	* 마지막 Row의 작업종료일자, 작업종료시간 완성하기
	* 마지막 Row의 작업종료일자, 작업종료시간이 입력되지 않은경우
	* 오더 종료일자, 종료시간을
	* 마지막 Row의 작업종료일자, 작업종료시간으로 설정하기
	**/
	if ($c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(ds_orderWrkPathStep.getRowCount(), "wrkEndDt")))
		ds_orderWrkPathStep.setCellData(ds_orderWrkPathStep.getRowCount(), "wrkEndDt", ds_order.getCellData(0, "wrkEndDt"));

	if ($c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(ds_orderWrkPathStep.getRowCount(), "wrkEndHh")))
		ds_orderWrkPathStep.setCellData(ds_orderWrkPathStep.getRowCount(), "wrkEndHh", ds_order.getCellData(0, "wrkEndHh"));
};

scwin.ds_orderWrkPathStep_onrowpositionchange = function (info) {
	if (scwin.v_row > 0) {
		// 작업시작일자, 작업시작시간 변경시 이전 row의 작업종료일자, 작업종료시간 변경
		if (scwin.v_row > 1) {
			if (!$c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkStDt").trim()) && ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkStDt") != ds_orderWrkPathStep.getOriginalCellData(scwin.v_row, "wrkStDt"))
				ds_orderWrkPathStep.setCellData(eval(scwin.v_row-1), "wrkEndDt", ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkStDt"));

			if (!$c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkStHh").trim()) && ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkStHh") != ds_orderWrkPathStep.getOriginalCellData(scwin.v_row, "wrkStHh"))
				ds_orderWrkPathStep.setCellData(eval(scwin.v_row-1), "wrkEndHh", ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkStHh"));

		}
		// 작업종료일자, 작업종료시간 변경시 이후 row의 작업시작일자, 작업시작시간 변경
		if (scwin.v_row < ds_orderWrkPathStep.getRowCount()) {
			if (!$c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkEndDt").trim()) && ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkEndDt") != ds_orderWrkPathStep.getOriginalCellData(scwin.v_row, "wrkEndDt"))
				ds_orderWrkPathStep.setCellData(eval(scwin.v_row + 1), "wrkStDt", ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkEndDt"));

			if (!$c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkEndHh").trim()) && ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkEndHh") != ds_orderWrkPathStep.getOriginalCellData(scwin.v_row, "wrkEndHh")) {
				ds_orderWrkPathStep.setCellData(eval(scwin.v_row + 1), "wrkStHh", ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkEndHh"));
			}
		}
	}

	scwin.v_row = info.newRowIndex;

	/**
	* 첫번째 작업단계 작업 시작일자/시간
	* 마지막 작업단계 작업 종료일자/시간 정보는 수정 할수 없음.
	*/

    var rowIndex = info.newRowIndex;
    var lastRowIndex = ds_orderWrkPathStep.getRowCount() - 1;

    if (gr_odrWrkPathStep.getReadOnly("grid") != true) {
        if (rowIndex == 0) {
            gr_odrWrkPathStep.setCellReadOnly(rowIndex, "wrkStDt", true);
            gr_odrWrkPathStep.setCellReadOnly(rowIndex, "wrkStHh", true);
            // gr_odrWrkPathStep.setColumnReadOnly("wrkStDt", true); 
            // gr_odrWrkPathStep.setColumnReadOnly("wrkStHh", true); 
        } else {
            gr_odrWrkPathStep.setCellReadOnly(rowIndex, "wrkStDt", false);
            gr_odrWrkPathStep.setCellReadOnly(rowIndex, "wrkStHh", false);
            // gr_odrWrkPathStep.setColumnReadOnly("wrkStDt", false); 
            // gr_odrWrkPathStep.setColumnReadOnly("wrkStHh", false);         
        }

        if (rowIndex == lastRowIndex) {
            gr_odrWrkPathStep.setCellReadOnly(rowIndex, "wrkEndDt", true);
            gr_odrWrkPathStep.setCellReadOnly(rowIndex, "wrkEndHh", true);
            // gr_odrWrkPathStep.setColumnReadOnly("wrkEndDt", true); 
            // gr_odrWrkPathStep.setColumnReadOnly("wrkEndHh", true);  
        } else {
            gr_odrWrkPathStep.setCellReadOnly(rowIndex, "wrkEndDt", false);
            gr_odrWrkPathStep.setCellReadOnly(rowIndex, "wrkEndHh", false);
            // gr_odrWrkPathStep.setColumnReadOnly("wrkEndDt", false); 
            // gr_odrWrkPathStep.setColumnReadOnly("wrkEndHh", false); 
        }
    }

};

