scwin.gr_odrWrkPathStep_CustomFormatter = function(data, formattedData, rowIndex, colIndex) {
    let columnId =  $c.util.getComponent(this.id).getColumnID(colIndex);
    let val = data, color = "black";

    if (columnId == "wrkPlClsNmV") {
        var wrkPlClsNm = ds_orderWrkPathStep.getCellData(rowIndex, 'wrkPlClsNm');

        if (wrkPlClsNm == '') {
            val = "→";
        } else {
            val = wrkPlClsNm;
        }
        // 특정 컬럼에 세로 병합 적용
        //gr_odrWrkPathStep.mergeCol(columnIndex, include)
        gr_odrWrkPathStep.mergeCol("wrkPlClsNmV", true);
    } else if (columnId == "wrkPlClsNm") {
        var wrkPlClsNm = ds_orderWrkPathStep.getCellData(rowIndex, 'wrkPlClsNm');

        if (wrkPlClsNm == '') {
            val = "→";
        } else {
            val = wrkPlClsNm;
        }
        // 특정 컬럼에 세로 병합 적용
        //gr_odrWrkPathStep.mergeCol(columnIndex, include)
        gr_odrWrkPathStep.mergeCol("wrkPlClsNmV", true);
    }

    return val;
};

scwin.gr_odrWrkPathStep_onviewchange = function (info) {
    var colId = info.colId
    var colIndex = info.colIndex
    var newValue = info.newValue
    var oldValue = info.oldValue
    var rowIndex = info.rowIndex

	scwin.v_colid = colId;

	if (scwin.v_row >= 0) {
		// 작업시작일자, 작업시작시간 변경시 이전 row의 작업종료일자, 작업종료시간 변경
		if (scwin.v_row > 0) {
			if (!$c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkStDt").trim()) && ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkStDt") != ds_orderWrkPathStep.getOriginalCellData(scwin.v_row, "wrkStDt"))
				ds_orderWrkPathStep.setCellData(eval(scwin.v_row -1), "wrkEndDt", ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkStDt"));

			if (!$c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkStHh").trim()) && ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkStHh") != ds_orderWrkPathStep.getOriginalCellData(scwin.v_row, "wrkStHh"))
				ds_orderWrkPathStep.setCellData(eval(scwin.v_row -1), "wrkEndHh", ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkStHh"));

		}
		// 작업종료일자, 작업종료시간 변경시 이후 row의 작업시작일자, 작업시작시간 변경
		if (scwin.v_row < ds_orderWrkPathStep.getRowCount()-1) {
			if (!$c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkEndDt").trim()) && ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkEndDt") != ds_orderWrkPathStep.getOriginalCellData(scwin.v_row, "wrkEndDt"))
				ds_orderWrkPathStep.setCellData(eval(scwin.v_row + 1), "wrkStDt", ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkEndDt"));

			if (!$c.gus.cfIsNull(ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkEndHh").trim()) && ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkEndHh") != ds_orderWrkPathStep.getOriginalCellData(scwin.v_row, "wrkEndHh")) {
				ds_orderWrkPathStep.setCellData(eval(scwin.v_row + 1), "wrkStHh", ds_orderWrkPathStep.getCellData(scwin.v_row, "wrkEndHh"));
			}

		}
	}
	scwin.v_row = rowIndex;
};

